async (params, browser) => {
  // Open Jira issue
  await browser.open(`${params.jira_url}/browse/${params.issue_key}`)

  // Let page load
  await browser.wait(2000)

  // Fetch issue details via REST API
  const result = await browser.evaluate(`const baseUrl = params.jira_url.replace(/\/$/, ''); const resp = await fetch(baseUrl + '/rest/api/3/issue/' + params.issue_key + '?fields=summary,description,status,assignee,reporter,priority,issuetype,labels,created,updated,comment', { credentials: 'same-origin' }); if (!resp.ok) throw new Error('Jira API error: ' + resp.status); const i = await resp.json(); const comments = (i.fields.comment?.comments || []).slice(-5).map(c => ({ author: c.author?.displayName || '', body: c.body?.content?.map(b => b.content?.map(t => t.text).join('')).join('\n') || '', created: c.created })); return { key: i.key, summary: i.fields.summary, description: i.fields.description?.content?.map(b => b.content?.map(t => t.text).join('')).join('\n') || '', status: i.fields.status?.name || '', assignee: i.fields.assignee?.displayName || 'Unassigned', reporter: i.fields.reporter?.displayName || '', priority: i.fields.priority?.name || '', type: i.fields.issuetype?.name || '', labels: i.fields.labels || [], created: i.fields.created, updated: i.fields.updated, recent_comments: comments }`)

  return result
}
